def get_session(info: Info):
    return info.context["db"]


def prime_and_get(info: Info, key: str, model_id: int):
    cache: Dict[Tuple[str, int], object] = info.context.setdefault("obj_cache", {})
    return cache.get((key, model_id))


def cache_set(info: Info, key: str, model_id: int, obj):
    cache: Dict[Tuple[str, int], object] = info.context.setdefault("obj_cache", {})
    cache[(key, model_id)] = obj


def parse_requested_product_tree(info: Info) -> Dict[str, bool]:
    requested = {"seller": False, "reviews": False, "categories": False, "images": False}

    def walk(selections):
        for sel in selections or []:
            name = getattr(sel, "name", None)
            if name in requested:
                requested[name] = True
            sub = getattr(sel, "selections", None)
            if sub:
                walk(sub)

    for field in info.selected_fields:
        if field.name in ("product", "products", "searchProducts"):
            walk(field.selections)
    return requested


