    @strawberry.field
    def searchProducts(
        self,
        info: Info,
        query: str,
        limit: int = 50,
        offset: int = 0,
    ) -> List[Product]:
        session = get_session(info)
        req = parse_requested_product_tree(info)
        opts = []
        if req["seller"]:
            opts.append(selectinload(ProductModel.seller))
        if req["reviews"]:
            opts.append(selectinload(ProductModel.reviews))
        if req["categories"]:
            opts.append(selectinload(ProductModel.categories))
        if req["images"]:
            opts.append(selectinload(ProductModel.images))

        like = f"%{query}%"
        stmt = (
            select(ProductModel)
            .where((ProductModel.name.ilike(like)) | (ProductModel.sku.ilike(like)) | (ProductModel.description.ilike(like)))
            .order_by(ProductModel.id.asc())
            .limit(max(0, limit))
            .offset(max(0, offset))
            .options(*opts)
        )
        ms = session.execute(stmt).scalars().all()
