@strawberry.type
class Mutation:
    @strawberry.mutation
    def createSeller(self, info: Info, name: str, rating: Optional[float] = None) -> Seller:
        session = get_session(info)
        s = SellerModel(name=name, rating=rating)
        session.add(s)
        session.commit()
        session.refresh(s)
        return Seller(id=str(s.id), name=s.name, rating=s.rating, created_at=s.created_at)

    @strawberry.mutation
    def createCategory(self, info: Info, name: str) -> Category:
        session = get_session(info)
        c = CategoryModel(name=name)
        session.add(c)
        session.commit()
        session.refresh(c)
        return Category(id=str(c.id), name=c.name)

    @strawberry.mutation
    def createProduct(
        self,
        info: Info,
        sku: str,
        name: str,
        price: float,
        seller_id: strawberry.ID,
        currency: str = "USD",
        description: Optional[str] = None,
        category_ids: Optional[List[strawberry.ID]] = None,
        image_urls: Optional[List[str]] = None,
    ) -> Product:
        session = get_session(info)
        seller = session.get(SellerModel, int(seller_id))
        if not seller:
            raise ValueError("Seller not found")

        p = ProductModel(
            sku=sku,
            name=name,
            description=description,
            price=price,
            currency=currency,
            seller=seller,
        )

        if category_ids:
            cats = session.execute(select(CategoryModel).where(CategoryModel.id.in_([int(x) for x in category_ids]))).scalars().all()
            p.categories = cats

        if image_urls:
            p.images = [ImageModel(url=u, sort_order=i) for i, u in enumerate(image_urls)]

        session.add(p)
        session.commit()
        session.refresh(p)
        cache_set(info, "product", int(p.id), p)
        return to_product_type(p)

    @strawberry.mutation
    def addReview(
        self,
        info: Info,
        product_id: strawberry.ID,
        author: str,
        rating: int,
        title: Optional[str] = None,
        body: Optional[str] = None,
    ) -> Review:
        session = get_session(info)
        p = session.get(ProductModel, int(product_id))
        if not p:
            raise ValueError("Product not found")
        r = ReviewModel(product=p, author=author, rating=rating, title=title, body=body)
        session.add(r)
        session.commit()
        session.refresh(r)
        return Review(id=str(r.id), author=r.author, rating=r.rating, title=r.title, body=r.body, created_at=r.created_at)

    @strawberry.mutation
    def addImage(
        self,
        info: Info,
        product_id: strawberry.ID,
        url: str,
        alt_text: Optional[str] = None,
        sort_order: int = 0,
    ) -> Image:
        session = get_session(info)
        p = session.get(ProductModel, int(product_id))
        if not p:
            raise ValueError("Product not found")
        img = ImageModel(product=p, url=url, alt_text=alt_text, sort_order=sort_order)
        session.add(img)
        session.commit()
        session.refresh(img)
        return Image(id=str(img.id), url=img.url, alt_text=img.alt_text, sort_order=img.sort_order)


schema = strawberry.Schema(query=Query, mutation=Mutation)


async def get_context():
    db = SessionLocal()
    try:
        return {"db": db, "obj_cache": {}}
    finally:
        pass


async def on_shutdown():
    try:
        SessionLocal.remove()
    except Exception:
        pass


app = GraphQL(schema, context_getter=get_context)